from flask import Flask, request, jsonify
from elasticapm.contrib.flask import ElasticAPM
from sqlalchemy import create_engine, Column, Integer, String
from sqlalchemy.orm import sessionmaker
from sqlalchemy.ext.declarative import declarative_base
import time
import os

# --- Flask Application Setup ---
app = Flask(__name__)

# --- APM Configuration ---
# Configure Elastic APM via Flask app.config
# For production, these values should ideally come from environment variables
# and the APM server URL should be a real server address.
app.config['ELASTIC_APM'] = {
    'service_name': os.getenv('APM_SERVICE_NAME', 'python-apm-app'),
    'server_url': os.getenv('APM_SERVER_URL', 'http://localhost:8200'),
    'environment': os.getenv('APM_ENVIRONMENT', 'development'),
    'capture_body': 'all',  # Capture full request and response bodies
    'record_sql_statements': 'all',  # Capture full SQL queries
    'stack_trace_limit': -1,  # Capture full stack traces for errors and slow events
    'transaction_sample_rate': 1.0,  # Sample all transactions for demonstration
    'debug': True, # Enable debug logging for the APM agent
}

# Initialize Elastic APM
apm = ElasticAPM(app)

# --- Database Setup (SQLite in-memory for demonstration) ---
engine = create_engine('sqlite:///:memory:')
Base = declarative_base()

class User(Base):
    __tablename__ = 'users'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    email = Column(String)

    def __repr__(self):
        return f"<User(id={self.id}, name='{self.name}', email='{self.email}')>"

# Create tables
Base.metadata.create_all(engine)

# Session factory
Session = sessionmaker(bind=engine)

# --- Flask Routes ---

@app.route('/')
def hello_world():
    """A simple route that just returns a string."""
    return "Hello, APM Instrumented World!"

@app.route('/db_query')
def db_query():
    """
    A route that performs database operations (insert and select)
    to demonstrate SQL query capture.
    """
    session = Session()
    try:
        # Insert a new user
        new_user = User(name=f"TestUser_{time.time()}", email=f"user_{time.time()}@example.com")
        session.add(new_user)
        session.commit()
        inserted_id = new_user.id

        # Query all users
        users = session.query(User).all()
        user_names = [user.name for user in users]

        return jsonify({
            "message": f"User with ID {inserted_id} added and {len(users)} users retrieved.",
            "users": user_names,
            "request_body_capture_note": "This endpoint doesn't process request body, but if it did, 'capture_body: all' would capture it."
        })
    except Exception as e:
        session.rollback()
        apm.capture_exception() # Explicitly capture the exception
        return jsonify({"error": str(e)}), 500
    finally:
        session.close()

@app.route('/error')
def trigger_error():
    """
    A route that intentionally raises an exception to demonstrate
    error capture with full stack traces.
    """
    # Simulate a deep call stack
    def func_c():
        raise ValueError("This is an intentional error for APM testing!")

    def func_b():
        return func_c()

    def func_a():
        return func_b()

    return func_a()

@app.route('/custom_span')
def custom_span_example():
    """
    A route demonstrating how to create custom spans for specific operations
    within a transaction.
    """
    with apm.client.begin_span('my_custom_operation', 'custom.processing'):
        # Simulate some work
        time.sleep(0.05) # Small delay

        with apm.client.begin_span('sub_operation_1', 'custom.logic'):
            result1 = 10 * 5
            time.sleep(0.02)

        with apm.client.begin_span('sub_operation_2', 'custom.io'):
            # Simulate a network call or I/O
            response = {"status": "success", "data": result1}
            time.sleep(0.03)

    return jsonify({"message": "Custom spans recorded.", "result": response})

@app.route('/echo', methods=['GET', 'POST', 'PUT'])
def echo():
    """
    An endpoint to demonstrate request body and header capture.
    """
    data = request.json if request.is_json else request.data.decode('utf-8')
    headers = dict(request.headers)
    method = request.method

    return jsonify({
        "method": method,
        "received_headers": headers,
        "received_body": data,
        "note": "Check APM for full request/response body and headers."
    })

